@app.route('/api/inventory/<product>')
@track_metrics
def get_inventory(product):
    inventory = random.randint(0, 1000)
    INVENTORY_LEVEL.labels(product=product).set(inventory)
    
    return jsonify({
        'product': product,
        'quantity': inventory
    })


@app.route('/api/cache/get/<key>')
@track_metrics
def cache_get(key):
    hit = random.choice([True, False])
    result = 'hit' if hit else 'miss'
    
    CACHE_OPERATIONS.labels(operation='get', result=result).inc()
    
    if hit:
        return jsonify({'key': key, 'value': f'cached_value_{key}'})
    else:
        return jsonify({'key': key, 'value': None}), 404


@app.route('/api/cache/set', methods=['POST'])
@track_metrics
def cache_set():
    data = request.get_json() or {}
    
    CACHE_OPERATIONS.labels(operation='set', result='success').inc()
    
    return jsonify({'status': 'cached', 'key': data.get('key')}), 201


