@app.route('/api/business/metrics')
@track_metrics
def business_metrics():
    ACTIVE_USERS.set(random.randint(100, 500))
    
    for product in ['product_a', 'product_b', 'product_c']:
        INVENTORY_LEVEL.labels(product=product).set(random.randint(50, 500))
    
    DATABASE_CONNECTIONS.labels(state='active').set(random.randint(10, 30))
    DATABASE_CONNECTIONS.labels(state='idle').set(random.randint(20, 40))
    
    return jsonify({
        'message': 'Business metrics updated',
        'timestamp': time.time()
    })


@app.errorhandler(404)
def not_found(error):
    REQUEST_COUNT.labels(method=request.method, endpoint='not_found', status=404).inc()
    return jsonify({'error': 'Not found'}), 404


@app.errorhandler(500)
def internal_error(error):
    REQUEST_COUNT.labels(method=request.method, endpoint='error', status=500).inc()
    ERROR_COUNT.labels(type='InternalServerError').inc()
    return jsonify({'error': 'Internal server error'}), 500


